INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('SUMMIT_1: Le email multivariate testing: au lieu de A/B (1 variable), tester 3 variables simultanement (sujet × preheader × CTA) avec un outil comme Brevo ou Mailchimp. Necessite 5000+ contacts.', 'Email multivariate: 3 variables simultanees. Necessite 5000+ contacts', 'email', 'best_practice', 0.80, 'summit', 'system'),
('SUMMIT_2: Le commercial stakeholder mapping canvas: pour chaque deal B2B, dessiner: decision maker (signe), champion (pousse), influencer (guide), gatekeeper (bloque), user (utilise).', 'Stakeholder canvas: DM + champion + influencer + gatekeeper + user', 'commercial', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_3: Le content creation ROI: temps de creation × taux horaire = cout. Trafic genere × CVR × deal value = revenu. Revenu/cout = ROI. Tracker pour chaque type de contenu.', 'Content ROI: (trafic × CVR × deal value) / (temps × taux horaire)', 'content', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_4: Le SEO site speed optimization checklist: 1) images WebP lazy-loaded, 2) JS defer/async, 3) CSS critical inline, 4) CDN, 5) cache headers, 6) compression gzip/brotli.', 'Speed checklist: WebP+lazy + JS defer + CSS inline + CDN + cache + compression', 'seo', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_5: Le ad audience testing framework: tester 1 audience avec 3 creatives. Si 0 fonctionne = audience mauvaise. Si 1+ fonctionne = audience bonne, optimiser la creative gagnante.', 'Audience test: 1 audience × 3 creatives. 0 ok = audience mauvaise. 1+ = bonne', 'ads', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_6: Le DM Instagram automation ethics: l automatisation est acceptee pour le warm-up (likes, follows) mais les DMs eux-memes doivent etre personnalises manuellement ou par IA contextuelle.', 'DM ethics: auto warm-up ok. DMs = personnalises manuellement ou IA contextuelle', 'dm_instagram', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_7: Le WhatsApp message optimization: les messages < 100 mots ont 2x plus de lectures que les messages > 200 mots. Court et direct > long et detaille.', 'WhatsApp: < 100 mots = 2x lectures vs > 200 mots. Court > long', 'whatsapp', 'insight', 0.82, 'summit', 'system'),
('SUMMIT_8: Le chatbot NLU training best practices: min 10 exemples par intent, varier la formulation, inclure les fautes de frappe courantes, tester avec des users reels.', 'Chatbot NLU: 10 exemples/intent + varier formulations + fautes + test users reels', 'chatbot', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_9: Le GMaps category selection strategy: choisir la categorie primaire la plus specifique possible (ex: Restaurant italien > Restaurant). Ajouter 2-3 categories secondaires pertinentes.', 'GMaps categories: primaire plus specifique possible + 2-3 secondaires pertinentes', 'gmaps', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_10: Le TikTok sound selection science: les sons trending < 50K videos = meilleure portee (pas sature). Les sons > 1M videos = trop sature, la video se noie.', 'TikTok sons: trending < 50K videos = meilleure portee. > 1M = trop sature', 'tiktok_comments', 'insight', 0.82, 'summit', 'system'),
('SUMMIT_11: Le CEO data-informed vs data-driven: les donnees INFORMENT la decision mais ne la PRENNENT pas. L intuition du fondateur + les donnees = meilleure decision.', 'CEO: data informed > data driven. Intuition + donnees = meilleure decision', 'ceo', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_12: Le retention NRR decomposition: NRR = 100% - gross churn% + expansion%. Si expansion > churn = NRR > 100% = croissance sans nouveaux clients.', 'NRR = 100% - churn + expansion. Expansion > churn = croissance sans nouveaux', 'retention', 'insight', 0.85, 'summit', 'system'),
('SUMMIT_13: Le onboarding social proof injection: montrer dans l onboarding combien d autres utilisateurs du meme secteur utilisent deja le produit. "327 restaurants utilisent deja KeiroAI."', 'Onboarding social proof: X utilisateurs du meme secteur utilisent deja', 'onboarding', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_14: Le comptable SaaS revenue recognition: les revenus sont reconnus au prorata sur la duree de l abonnement. Un paiement annuel de 1200€ = 100€/mois de revenu reconnu.', 'Revenue recognition SaaS: prorata duree abo. 1200€ annuel = 100€/mois reconnu', 'comptable', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_15: Le RH team composition principle: chaque equipe a besoin de 3 profils: visionnaire (idees), executeur (fait), analyste (mesure). Les 3 ensemble = equilibre parfait.', 'Team composition: visionnaire + executeur + analyste = equilibre parfait', 'rh', 'insight', 0.78, 'summit', 'system'),
('SUMMIT_16: Le marketing positioning refresh annual: chaque annee, reevaluer le positionnement. Le marche change, les concurrents evoluent, les clients aussi.', 'Positioning refresh annuel: marche change, concurrents evoluent, clients aussi', 'marketing', 'best_practice', 0.78, 'summit', 'system'),
('SUMMIT_17: Le cross-agent conflict resolution: quand 2 agents ciblent le meme prospect en meme temps → regle: 48h de cooling entre contacts differents. Le CEO arbitre.', 'Cross-agent conflict: 48h cooling entre contacts. CEO arbitre', NULL, 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_18: Le customer success health monitoring: verifier le health score de CHAQUE client premium 1x/semaine. Les clients non-premium 1x/mois. Red flag = action 48h.', 'Health monitoring: premium 1x/sem, non-premium 1x/mois. Red flag = action 48h', NULL, 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_19: Le KeiroAI auto-healing system: quand un agent echoue 3x sur la meme action → analyser le pattern → ajuster automatiquement → re-executer. Self-healing agents.', 'KeiroAI auto-healing: 3 echecs meme action → analyser → ajuster auto → re-executer', NULL, 'best_practice', 0.88, 'summit', 'system'),
('SUMMIT_20: Le KeiroAI knowledge graph: chaque learning est lie aux autres par des relations semantiques. Le RAG ne cherche pas juste des mots-cles, il comprend les connexions.', 'KeiroAI knowledge graph: learnings lies par relations semantiques. Comprend connexions', NULL, 'insight', 0.85, 'summit', 'system'),
('SUMMIT_21: Le email deliverability monitoring dashboard: sender score, inbox placement rate, bounce rate, spam complaint rate, blacklist status. Verifier quotidiennement.', 'Email deliverability dashboard: sender score+IPR+bounce+spam+blacklist. Quotidien', 'email', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_22: Le commercial ICP refinement: tous les 3 mois, analyser les 20 meilleurs clients (plus haute LTV) et mettre a jour l ICP base sur leurs caracteristiques communes.', 'ICP refinement trimestriel: top 20 clients LTV → MAJ ICP', 'commercial', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_23: Le content distribution amplification: pour chaque contenu publie: 1) partager sur tous les reseaux, 2) envoyer en newsletter, 3) commenter dans les groupes, 4) booster en ads si top performer.', 'Content distribution: social + newsletter + groupes + ads si top performer', 'content', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_24: Le SEO competitive gap analysis: utiliser Ahrefs Content Gap pour trouver les mots-cles ou les 3 concurrents rankent et pas vous. Ce sont vos plus grosses opportunites.', 'Competitive gap Ahrefs: mots-cles 3 concurrents rankent pas vous = opportunites', 'seo', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_25: Le ad platform diversification: ne jamais mettre 100% du budget sur 1 plateforme. Split: 50-60% Meta, 20-30% Google, 10-20% TikTok/LinkedIn. Diversifier le risque.', 'Ad diversification: 50-60% Meta + 20-30% Google + 10-20% TikTok/LI. Jamais 100% sur 1', 'ads', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_26: Le DM targeting precision: cibler les profils qui: 1) ont 1K-10K followers, 2) postent regulierement, 3) sont dans le secteur cible, 4) engagent avec du contenu similaire.', 'DM targeting: 1K-10K followers + actifs + secteur + engagent similaire', 'dm_instagram', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_27: Le WhatsApp group strategy: creer un groupe exclusif pour les clients VIP. Partager des offres exclusives, des astuces, du contenu premium. Max 50 membres pour la qualite.', 'WhatsApp groupe VIP: offres exclusives + astuces + premium. Max 50 membres', 'whatsapp', 'best_practice', 0.78, 'summit', 'system'),
('SUMMIT_28: Le chatbot visual flow builder: utiliser un outil visuel (Botpress, Voiceflow) pour designer les flows conversationnels avant de coder. Prototyper rapidement.', 'Chatbot flow builder visuel: designer flows avant coder. Prototyper vite', 'chatbot', 'best_practice', 0.78, 'summit', 'system'),
('SUMMIT_29: Le GMaps competitive benchmarking: comparer ses metriques (note, avis, photos, posts) avec les 5 concurrents directs. Identifier les ecarts et les combler.', 'GMaps benchmark: comparer note+avis+photos+posts avec 5 concurrents. Combler ecarts', 'gmaps', 'best_practice', 0.80, 'summit', 'system'),
('SUMMIT_30: Le TikTok creator economy: les createurs avec 10K+ followers gagnent 100-500€ par partenariat marque. A 100K+, 1000-5000€. C est un canal d acquisition rentable.', 'TikTok creator economy: 10K+ = 100-500€/partenariat. 100K+ = 1-5K€', 'tiktok_comments', 'insight', 0.78, 'summit', 'system'),
('SUMMIT_31: Le CEO weekly scorecard: 5 metriques critiques avec objectif + reel + ecart + tendance. Si 3/5 en rouge = urgence. Si 5/5 en vert = celebrer.', 'CEO scorecard hebdo: 5 metriques objectif+reel+ecart+tendance. 3/5 rouge = urgence', 'ceo', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_32: Le retention product stickiness measurement: compter le nombre de workflows/integrations que le client a configure. Plus de workflows = plus de switching cost = moins de churn.', 'Stickiness: nombre workflows/integrations = switching cost = moins churn', 'retention', 'insight', 0.85, 'summit', 'system'),
('SUMMIT_33: Le onboarding completion incentive design: badge digital + email de felicitations + deblocage feature bonus + 100 credits offerts. Gamification = +40% completion.', 'Onboarding incentive: badge + felicitations + feature bonus + credits = +40% completion', 'onboarding', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_34: Le comptable financial health score: MRR growth (25pts) + churn rate (25pts) + gross margin (20pts) + runway (15pts) + LTV/CAC (15pts). Score > 75 = sain.', 'Financial health score: MRR growth 25 + churn 25 + margin 20 + runway 15 + LTV/CAC 15. > 75 = sain', 'comptable', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_35: Le RH performance review calibration: les managers se reunissent pour comparer leurs evaluations et s assurer de la coherence des notes a travers l entreprise.', 'Calibration review: managers comparent evaluations = coherence notes', 'rh', 'best_practice', 0.78, 'summit', 'system'),
('SUMMIT_36: Le marketing brand health monitoring: tracker aided awareness, unaided awareness, NPS, share of voice, brand sentiment mensuellement. Tendances > chiffres absolus.', 'Brand health: awareness + NPS + share of voice + sentiment. Tendances > absolus', 'marketing', 'best_practice', 0.80, 'summit', 'system'),
('SUMMIT_37: Le inter-agent data quality protocol: les donnees partagees entre agents doivent etre verifiees, a jour et completes. Donnees sales = decisions mauvaises pour tous.', 'Data quality: donnees partagees verifiees + a jour + completes. Sales = mauvaises decisions', NULL, 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_38: Le customer lifetime value optimization levers: augmenter ARPU (upsell), augmenter duree vie (retention), augmenter frequence (engagement). Les 3 multiplient le LTV.', 'LTV optimization: ARPU (upsell) × duree (retention) × frequence (engagement)', NULL, 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_39: Le KeiroAI competitive intelligence system: surveiller les 5 principaux concurrents (features, pricing, reviews, contenu) et ajuster la strategie en consequence.', 'KeiroAI competitive intel: 5 concurrents (features+pricing+reviews+contenu)', 'ceo', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_40: Le KeiroAI ultimate vision: une plateforme ou chaque entrepreneur a acces a une equipe marketing complete, intelligente, qui apprend et s ameliore chaque jour. L avenir du marketing IA.', 'KeiroAI ultimate: equipe marketing IA complete, intelligente, auto-amelioration. L avenir', 'ceo', 'best_practice', 0.95, 'summit', 'system'),
('SUMMIT_41: Le email list segmentation maturity model: L1 = pas de segmentation. L2 = par plan/source. L3 = par comportement. L4 = par intent. L5 = predictif IA. Viser L3+.', 'Segmentation maturity: L1 aucune → L5 predictif IA. Viser L3+', 'email', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_42: Le commercial objection reframe technique: transformer chaque objection en question. "C est trop cher" → "Qu est-ce qui justifierait cet investissement pour vous?"', 'Objection reframe: transformer en question. Trop cher → qu est-ce qui justifierait?', 'commercial', 'best_practice', 0.85, 'summit', 'system'),
('SUMMIT_43: Le content emotional resonance mapping: chaque persona a 2-3 emotions dominantes (frustration, ambition, peur, fierte). Cibler ces emotions dans le contenu.', 'Emotional resonance: 2-3 emotions dominantes par persona. Cibler dans contenu', 'content', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_44: Le SEO answer engine optimization: avec l essor des IA (ChatGPT, Perplexity, Google SGE), optimiser pour etre LA source citee. Contenu factuel, structure, source.', 'Answer engine optimization: etre LA source citee par IA. Factuel + structure + source', 'seo', 'insight', 0.85, 'summit', 'system'),
('SUMMIT_45: Le ad incrementality measurement: le vrai test = couper les ads dans une zone et comparer les ventes vs une zone avec ads. La difference = l impact reel des ads.', 'Incrementality: couper ads 1 zone vs zone avec = impact reel ads', 'ads', 'best_practice', 0.80, 'summit', 'system'),
('SUMMIT_46: Le DM Instagram qualification speed: les 2 premieres questions du DM doivent qualifier (secteur + besoin). Si fit → approfondir. Si pas fit → remercier et passer au suivant.', 'DM qualification: 2 premieres questions (secteur+besoin). Fit → approfondir. Pas → suivant', 'dm_instagram', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_47: Le WhatsApp after-sales engagement: suivi 48h post-achat + demande satisfaction J+7 + offre cross-sell J+14 + demande avis J+21 + programme fidelite J+30.', 'WhatsApp after-sales: 48h suivi → J7 satisfaction → J14 cross-sell → J21 avis → J30 fidelite', 'whatsapp', 'best_practice', 0.82, 'summit', 'system'),
('SUMMIT_48: Le chatbot analytics deep dive: conversation funnel (start → engage → resolve → CSAT), drop-off points, top failed intents, average messages per conversation.', 'Chatbot analytics deep: funnel + drop-off + failed intents + avg messages', 'chatbot', 'best_practice', 0.80, 'summit', 'system'),
('SUMMIT_49: Le GMaps local SEO trinity: 1) Google Business Profile optimise a 100%, 2) citations NAP coherentes sur 50+ annuaires, 3) avis recents et frequents > 5/mois.', 'Local SEO trinity: GBP 100% + NAP 50+ annuaires + avis > 5/mois', 'gmaps', 'best_practice', 0.88, 'summit', 'system'),
('SUMMIT_50: Le TikTok content production system: 1 journee de tournage/mois = 15-20 videos raw → editer en 30-40 clips → planifier sur 30 jours → analyser → iterer.', 'TikTok production: 1j tournage/mois = 15-20 raw → 30-40 clips → 30j planifie → analyser', 'tiktok_comments', 'best_practice', 0.80, 'summit', 'system')
